solution_code:
#include <iostream>

namespace fast {
    int add(int x, int y) { return x + y; }
    int multiply(int x, int y) { return x * y; }
}

namespace safe {
    int add(int x, int y) { return x + y + 1; }
    int multiply(int x, int y) { return x * y - 1; }
}

int main() {
    int a{}, b{}, c{}, d{};
    std::cin >> a >> b >> c >> d;

    std::cout << "fast add: " << fast::add(a, b) << '\n';
    std::cout << "safe add: " << safe::add(a, b) << '\n';
    std::cout << "fast multiply: " << fast::multiply(c, d) << '\n';
    std::cout << "safe multiply: " << safe::multiply(c, d) << '\n';

    return 0;
}

