solution_code:
#include <iostream>

namespace mathtools {
    int add(int a, int b) { return a + b; }
    int subtract(int a, int b) { return a - b; }
    int multiply(int a, int b) { return a * b; }
}

int main() {
    int a{}, b{};
    std::cin >> a >> b;

    using mathtools::add;

    std::cout << "Sum: " << add(a, b) << '\n';
    std::cout << "Difference: " << mathtools::subtract(a, b) << '\n';
    std::cout << "Product: " << mathtools::multiply(a, b) << '\n';

    return 0;
}
